453→/// <summary>
454→/// 개별 WORD의 16비트 상태 뷰모델
455→/// </summary>
456→public class WordViewModel : INotifyPropertyChanged
457→{
458→    public string MwAddress { get; }
459→    public string Description { get; }
460→    public string Direction { get; }
461→    public bool IsWritable => Direction == "WRITE";
462→    public ObservableCollection<BitViewModel> Bits { get; } = [];
463→
