using System;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Threading;
using System.Threading.Tasks;
using System.Windows;
using AssembleMonitor.Features.Communication;
using AssembleMonitor.Models;
using static AssembleMonitor.Features.IoMonitor.MemoryMapDefinition;

namespace AssembleMonitor.Features.IoMonitor;

/// <summary>
/// I/O 모니터 뷰모델 — PLC 비트 데이터 실시간 표시 + 출력 제어
/// </summary>
public class IoMonitorViewModel : INotifyPropertyChanged, IDisposable
{
    private readonly XgtClient _client = new();
    private CancellationTokenSource? _cts;

    // 탭별 WORD 데이터
    public ObservableCollection<WordViewModel> InputWords { get; } = [];
    public ObservableCollection<WordViewModel> OutputWords { get; } = [];
    public ObservableCollection<WordViewModel> ServoSystemWords { get; } = [];

    // 출력 캐시 — 토글 시 현재 값 기반으로 비트 변경 후 쓰기
    private readonly ushort[] _outputCache = new ushort[10];

    // 서보/시스템 WRITE 캐시 — MW300,301,500 (ServoSystemWords index 0,1,4)
    private readonly ushort[] _servoSysCache = new ushort[6];
    // ServoSystemWords 인덱스 → MW 주소 매핑
    private static readonly int[] ServoSysMwAddresses = [300, 301, 400, 401, 500, 501];

    // 서보 파라미터 (DINT 값)
    private int _targetPos, _targetVel, _jogVel, _actPos, _actVel;
    private ushort _errCode, _actPosDeg;

    public int TargetPos { get => _targetPos; set { _targetPos = value; OnPropertyChanged(); } }
    public int TargetVel { get => _targetVel; set { _targetVel = value; OnPropertyChanged(); } }
    public int JogVel { get => _jogVel; set { _jogVel = value; OnPropertyChanged(); } }
    public int ActPos { get => _actPos; set { _actPos = value; OnPropertyChanged(); OnPropertyChanged(nameof(ActPosDegStr)); } }
    public int ActVel { get => _actVel; set { _actVel = value; OnPropertyChanged(); } }
    public ushort ErrCode { get => _errCode; set { _errCode = value; OnPropertyChanged(); } }
    public ushort ActPosDeg { get => _actPosDeg; set { _actPosDeg = value; OnPropertyChanged(); } }
    public string ActPosDegStr => $"{ActPos / 1000.0:F3}°";

    // U영역 모니터 (%UW0.9.0 ~ %UW0.9.1)
    private ushort _uw090Raw, _uw091Raw;
    private bool _uModuleRdy, _uPosEl, _uNegEl, _uDog, _uZPhase, _uOrgDone, _uDstDone;

    public bool UModuleRdy { get => _uModuleRdy; set { _uModuleRdy = value; OnPropertyChanged(); } }
    public bool UPosEl { get => _uPosEl; set { _uPosEl = value; OnPropertyChanged(); } }
    public bool UNegEl { get => _uNegEl; set { _uNegEl = value; OnPropertyChanged(); } }
    public bool UDog { get => _uDog; set { _uDog = value; OnPropertyChanged(); } }
    public bool UZPhase { get => _uZPhase; set { _uZPhase = value; OnPropertyChanged(); } }
    public bool UOrgDone { get => _uOrgDone; set { _uOrgDone = value; OnPropertyChanged(); } }
    public bool UDstDone { get => _uDstDone; set { _uDstDone = value; OnPropertyChanged(); } }
    public string Uw090Hex => $"0x{_uw090Raw:X4}";
    public string Uw091Hex => $"0x{_uw091Raw:X4}";

    // 서보 제어 상태
    private bool _stsMoving, _stsError, _stsRdy;
    private bool _rspHomeDone, _rspMoveDone, _rspHomeErr, _rspMoveErr, _rspResetDone;
    private string _lastServoCmd = "";

    public bool StsMoving { get => _stsMoving; set { _stsMoving = value; OnPropertyChanged(); } }
    public bool StsError { get => _stsError; set { _stsError = value; OnPropertyChanged(); } }
    public bool StsRdy { get => _stsRdy; set { _stsRdy = value; OnPropertyChanged(); } }
    public bool RspHomeDone { get => _rspHomeDone; set { _rspHomeDone = value; OnPropertyChanged(); } }
    public bool RspMoveDone { get => _rspMoveDone; set { _rspMoveDone = value; OnPropertyChanged(); } }
    public bool RspHomeErr { get => _rspHomeErr; set { _rspHomeErr = value; OnPropertyChanged(); } }
    public bool RspMoveErr { get => _rspMoveErr; set { _rspMoveErr = value; OnPropertyChanged(); } }
    public bool RspResetDone { get => _rspResetDone; set { _rspResetDone = value; OnPropertyChanged(); } }
    public string LastServoCmd { get => _lastServoCmd; set { _lastServoCmd = value; OnPropertyChanged(); } }

    // 서보 파라미터 입력
    private string _targetPosInput = "0";
    private string _targetVelInput = "10000";
    private bool _isMoveRel;

    public string TargetPosInput { get => _targetPosInput; set { _targetPosInput = value; OnPropertyChanged(); } }
    public string TargetVelInput { get => _targetVelInput; set { _targetVelInput = value; OnPropertyChanged(); } }
    public bool IsMoveRel { get => _isMoveRel; set { _isMoveRel = value; OnPropertyChanged(); } }

    // Heartbeat 카운터 (MW500: bit0~7=카운터, bit8=PC_READY)
    private byte _heartbeatCount;

    // PLC 상태 (MW501 파싱)
    private bool _plcCommOk, _plcEmoActive, _plcServoErr, _plcWdTimeout, _plcRun;
    private byte _plcHeartbeat;

    public bool PlcCommOk { get => _plcCommOk; set { _plcCommOk = value; OnPropertyChanged(); } }
    public bool PlcEmoActive { get => _plcEmoActive; set { _plcEmoActive = value; OnPropertyChanged(); } }
    public bool PlcServoErr { get => _plcServoErr; set { _plcServoErr = value; OnPropertyChanged(); } }
    public bool PlcWdTimeout { get => _plcWdTimeout; set { _plcWdTimeout = value; OnPropertyChanged(); } }
    public bool PlcRun { get => _plcRun; set { _plcRun = value; OnPropertyChanged(); } }
    public byte PlcHeartbeat { get => _plcHeartbeat; set { _plcHeartbeat = value; OnPropertyChanged(); } }

    // 연결 상태
    private string _connectionStatus = "미연결";
    private bool _isConnected;
    private int _cycleMs;

    public string ConnectionStatus { get => _connectionStatus; set { _connectionStatus = value; OnPropertyChanged(); } }
    public bool IsConnected { get => _isConnected; set { _isConnected = value; OnPropertyChanged(); } }
    public int CycleMs { get => _cycleMs; set { _cycleMs = value; OnPropertyChanged(); } }


    public IoMonitorViewModel()
    {
        foreach (var w in MemoryMapDefinition.InputMap)
            InputWords.Add(new WordViewModel(w));

        foreach (var w in MemoryMapDefinition.OutputMap)
            OutputWords.Add(new WordViewModel(w));

        foreach (var w in MemoryMapDefinition.ServoAndSystemMap)
            ServoSystemWords.Add(new WordViewModel(w));

        // JSON에서 사용자 편집 이름 로드
        IoMapConfig.Load(InputWords, OutputWords, ServoSystemWords);
    }

    /// <summary>
    /// 사용자 편집 이름 JSON 저장
    /// </summary>
    public void SaveBitNames()
    {
        IoMapConfig.Save(InputWords, OutputWords, ServoSystemWords);
    }

    public async Task ConnectAndStartAsync()
    {
        ConnectionStatus = "연결 중...";
        var ok = await _client.ConnectAsync();
        if (!ok)
        {
            ConnectionStatus = $"연결 실패 ({_client.IpAddress}:{_client.Port})";
            IsConnected = false;
            return;
        }

        IsConnected = true;
        ConnectionStatus = $"연결됨 ({_client.IpAddress})";

        _cts = new CancellationTokenSource();
        _ = Task.Run(() => PollLoopAsync(_cts.Token));
    }

    public async void StopAndDisconnect()
    {
        _cts?.Cancel();

        // PC_READY OFF 전송 후 해제
        if (_client.IsConnected)
        {
            try { await _client.WriteWordsAsync("%MW500", [0]); }
            catch { /* 무시 */ }
        }

        _client.Disconnect();
        IsConnected = false;
        PlcCommOk = false;
        PlcRun = false;
        ConnectionStatus = "미연결";
    }

    /// <summary>
    /// 출력 비트 토글 — 클릭 시 호출
    /// </summary>
    public async Task ToggleOutputBitAsync(int wordIndex, int bitIndex)
    {
        if (!IsConnected || wordIndex < 0 || wordIndex >= 10) return;

        // 현재 캐시 값에서 비트 토글
        _outputCache[wordIndex] ^= (ushort)(1 << bitIndex);

        // 해당 WORD 1개만 쓰기 (MW200 + wordIndex)
        var address = $"%MW{200 + wordIndex}";
        await _client.WriteWordsAsync(address, [_outputCache[wordIndex]]);
    }

    /// <summary>
    /// 서보/시스템 WRITE 영역 비트 토글 (MW300,301,500)
    /// </summary>
    public async Task ToggleServoSystemBitAsync(int wordIndex, int bitIndex)
    {
        if (!IsConnected || wordIndex < 0 || wordIndex >= ServoSysMwAddresses.Length) return;

        // WRITE 방향인지 확인
        if (wordIndex < ServoSystemWords.Count && ServoSystemWords[wordIndex].Direction != "WRITE") return;

        _servoSysCache[wordIndex] ^= (ushort)(1 << bitIndex);

        var address = $"%MW{ServoSysMwAddresses[wordIndex]}";
        await _client.WriteWordsAsync(address, [_servoSysCache[wordIndex]]);
    }

    // ======== JOG 제어 — %UW0.9.1 직접 쓰기 ========

    /// <summary>
    /// JOG 시작 (CW=정방향, CCW=역방향)
    /// %UW0.9.1: bit0=CW, bit1=CCW
    /// </summary>
    public async Task JogStartAsync(bool isCw)
    {
        if (!IsConnected) return;
        ushort jogVal = isCw ? (ushort)0x0001 : (ushort)0x0002;
        await _client.WriteWordsAsync("%UW0.9.1", [jogVal]);
        LastServoCmd = isCw ? "JOG CW ON" : "JOG CCW ON";
    }

    /// <summary>
    /// JOG 정지 — %UW0.9.1 = 0
    /// </summary>
    public async Task JogStopAsync()
    {
        if (!IsConnected) return;
        await _client.WriteWordsAsync("%UW0.9.1", [0x0000]);
        LastServoCmd = "JOG OFF";
    }

    // ======== 서보 명령 — MW300 비트 펄스 (SET → 500ms → CLEAR) ========

    /// <summary>
    /// MW300 특정 비트를 펄스로 ON → 대기 → OFF
    /// </summary>
    private async Task SendServoCommandAsync(int bit)
    {
        if (!IsConnected) return;
        // 현재 MW300 읽기 → 비트 SET → 쓰기 → 대기 → 비트 CLEAR → 쓰기
        var current = await _client.ReadWordsAsync("%MW300", 1);
        ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
        ushort newVal = (ushort)(val | (1 << bit));
        await _client.WriteWordsAsync("%MW300", [newVal]);
        await Task.Delay(500);
        newVal = (ushort)(val & ~(1 << bit));
        await _client.WriteWordsAsync("%MW300", [newVal]);
    }

    /// <summary>원점복귀 = MW300.bit0</summary>
    public async Task HomeAsync()
    {
        LastServoCmd = "원점복귀 실행...";
        await SendServoCommandAsync(0);
    }

    /// <summary>위치이동 = MW300.bit1 (파라미터 MW310~313 사전 쓰기)</summary>
    public async Task MoveAsync()
    {
        if (!int.TryParse(TargetPosInput, out var pos) ||
            !int.TryParse(TargetVelInput, out var vel))
        {
            LastServoCmd = "파라미터 입력 오류 (정수 필요)";
            return;
        }

        // MW301.1: 절대/상대 이동 모드
        ushort mw301 = (ushort)(IsMoveRel ? 0x0002 : 0x0000);
        await _client.WriteWordsAsync("%MW301", [mw301]);

        // MW310~313: 목표위치(DINT) + 목표속도(DINT)
        ushort posL = (ushort)(pos & 0xFFFF);
        ushort posH = (ushort)((pos >> 16) & 0xFFFF);
        ushort velL = (ushort)(vel & 0xFFFF);
        ushort velH = (ushort)((vel >> 16) & 0xFFFF);
        await _client.WriteWordsAsync("%MW310", [posL, posH, velL, velH]);

        LastServoCmd = $"이동: pos={pos}, vel={vel}, {(IsMoveRel ? "상대" : "절대")}";
        await SendServoCommandAsync(1);
    }

    /// <summary>즉시정지 = MW300.bit4</summary>
    public async Task StopAsync()
    {
        LastServoCmd = "즉시정지";
        await SendServoCommandAsync(4);
    }

    /// <summary>에러리셋 = MW300.bit5</summary>
    public async Task ResetAsync()
    {
        LastServoCmd = "에러 리셋";
        await SendServoCommandAsync(5);
    }

    /// <summary>
    /// 주기적으로 PLC MW 영역 읽기 + Heartbeat 쓰기
    /// </summary>
    private async Task PollLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            var sw = System.Diagnostics.Stopwatch.StartNew();
            try
            {
                // ★ Heartbeat 쓰기 — 매 사이클 최우선 (연결 중 무조건)
                _heartbeatCount++;
                ushort heartbeat = (ushort)(_heartbeatCount | 0x0100); // bit8=PC_READY
                await _client.WriteWordsAsync("%MW500", [heartbeat]);

                // 입력 읽기: MW100~109 (10 WORD)
                var inputs = await _client.ReadWordsAsync("%MW100", 10);
                if (inputs != null)
                    UpdateWordViewModels(InputWords, inputs);

                // 출력 읽기: MW200~209 (10 WORD) — readback
                var outputs = await _client.ReadWordsAsync("%MW200", 10);
                if (outputs != null)
                {
                    // 출력 캐시 동기화 (PLC에서 읽은 값 반영)
                    Array.Copy(outputs, _outputCache, Math.Min(outputs.Length, 10));
                    UpdateWordViewModels(OutputWords, outputs);
                }

                // 서보 명령 읽기: MW300~301 (2 WORD)
                var servoCmds = await _client.ReadWordsAsync("%MW300", 2);

                // 서보 파라미터 읽기: MW310~319 (10 WORD)
                var servoParams = await _client.ReadWordsAsync("%MW310", 10);

                // 서보 상태 읽기: MW400~401 (2 WORD)
                var servoStatus = await _client.ReadWordsAsync("%MW400", 2);

                // 서보 값 읽기: MW410~415 (6 WORD)
                var servoValues = await _client.ReadWordsAsync("%MW410", 6);

                // 시스템 읽기: MW500~501 (2 WORD)
                var system = await _client.ReadWordsAsync("%MW500", 2);

                // MW501 파싱 — PLC 상태 비트 + PLC 하트비트
                if (system is { Length: >= 2 })
                {
                    var mw501 = system[1];
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        PlcCommOk = (mw501 & 0x0001) != 0;
                        PlcEmoActive = (mw501 & 0x0002) != 0;
                        PlcServoErr = (mw501 & 0x0004) != 0;
                        PlcWdTimeout = (mw501 & 0x0008) != 0;
                        PlcRun = (mw501 & 0x0010) != 0;
                        PlcHeartbeat = (byte)(mw501 >> 8);
                    });
                }

                // 서보/시스템 탭 업데이트 + WRITE 캐시 동기화
                var servoSysData = new ushort[6];
                if (servoCmds != null) { servoSysData[0] = servoCmds[0]; servoSysData[1] = servoCmds[1]; }
                if (servoStatus != null) { servoSysData[2] = servoStatus[0]; servoSysData[3] = servoStatus[1]; }
                if (system != null) { servoSysData[4] = system[0]; servoSysData[5] = system[1]; }
                Array.Copy(servoSysData, _servoSysCache, 6);
                UpdateWordViewModels(ServoSystemWords, servoSysData);

                // 서보 파라미터/값 (DINT) 업데이트
                if (servoParams is { Length: >= 6 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        TargetPos = (int)(servoParams[0] | (servoParams[1] << 16));
                        TargetVel = (int)(servoParams[2] | (servoParams[3] << 16));
                        JogVel = (int)(servoParams[4] | (servoParams[5] << 16));
                    });
                }
                if (servoValues is { Length: >= 6 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        ActPos = (int)(servoValues[0] | (servoValues[1] << 16));
                        ActVel = (int)(servoValues[2] | (servoValues[3] << 16));
                        ErrCode = servoValues[4];
                        ActPosDeg = servoValues[5];
                    });
                }

                // 서보 상태 비트 파싱 (MW400: 상태, MW401: 응답)
                if (servoStatus is { Length: >= 2 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        StsMoving = (servoStatus[0] & 0x0001) != 0;
                        StsError = (servoStatus[0] & 0x0002) != 0;
                        StsRdy = (servoStatus[0] & 0x0010) != 0;
                        RspHomeDone = (servoStatus[1] & 0x0001) != 0;
                        RspMoveDone = (servoStatus[1] & 0x0002) != 0;
                        RspHomeErr = (servoStatus[1] & 0x0004) != 0;
                        RspMoveErr = (servoStatus[1] & 0x0008) != 0;
                        RspResetDone = (servoStatus[1] & 0x0010) != 0;
                    });
                }

                // U영역 모듈 상태 읽기: %UW0.9.0 ~ %UW0.9.1 (슬롯9 위치결정 모듈)
                var uwData = await _client.ReadWordsAsync("%UW0.9.0", 2);
                if (uwData is { Length: >= 2 })
                {
                    Application.Current?.Dispatcher.Invoke(() =>
                    {
                        _uw090Raw = uwData[0]; _uw091Raw = uwData[1];
                        UPosEl = (uwData[0] & 0x0001) != 0;      // bit0: +EL (상한)
                        UNegEl = (uwData[0] & 0x0002) != 0;      // bit1: -EL (하한)
                        UDog = (uwData[0] & 0x0004) != 0;        // bit2: DOG (근사원점)
                        UZPhase = (uwData[0] & 0x0008) != 0;     // bit3: Z상
                        UOrgDone = (uwData[0] & 0x0010) != 0;    // bit4: ORG 완료
                        UDstDone = (uwData[0] & 0x0020) != 0;    // bit5: DST 완료
                        UModuleRdy = (uwData[0] & 0x8000) != 0;  // bit15: 모듈 RDY
                        OnPropertyChanged(nameof(Uw090Hex));
                        OnPropertyChanged(nameof(Uw091Hex));
                    });
                }

                sw.Stop();
                Application.Current?.Dispatcher.Invoke(() =>
                {
                    CycleMs = (int)sw.ElapsedMilliseconds;
                    var plcSts = PlcRun ? "RUN" : (PlcWdTimeout ? "WD!" : "---");
                    ConnectionStatus = $"연결됨 ({_client.IpAddress}) — {CycleMs}ms | PC:{_heartbeatCount} PLC:{PlcHeartbeat} | {plcSts}";
                });
            }
            catch (Exception ex)
            {
                Application.Current?.Dispatcher.Invoke(() =>
                {
                    ConnectionStatus = $"통신 에러: {ex.Message}";
                });
            }

            // Delay 없음 — 통신 사이클(~50ms) 자체가 주기
            await Task.Yield();
        }
    }

    private void UpdateWordViewModels(ObservableCollection<WordViewModel> vms, ushort[] data)
    {
        Application.Current?.Dispatcher.Invoke(() =>
        {
            for (int i = 0; i < Math.Min(vms.Count, data.Length); i++)
                vms[i].UpdateValue(data[i]);
        });
    }


    public void Dispose()
    {
        StopAndDisconnect();
        _client.Dispose();
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    protected void OnPropertyChanged([CallerMemberName] string? name = null)
        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
}

/// <summary>
/// 개별 WORD의 16비트 상태 뷰모델
/// </summary>
public class WordViewModel : INotifyPropertyChanged
{
    public string MwAddress { get; }
    public string Description { get; }
    public string Direction { get; }
    public bool IsWritable => Direction == "WRITE";
    public ObservableCollection<BitViewModel> Bits { get; } = [];

    private ushort _rawValue;
    public ushort RawValue { get => _rawValue; set { _rawValue = value; OnPropertyChanged(); OnPropertyChanged(nameof(HexValue)); } }
    public string HexValue => $"0x{RawValue:X4}";

    public WordViewModel(WordInfo info)
    {
        MwAddress = info.MwAddress;
        Description = info.Description;
        Direction = info.Direction;

        foreach (var bit in info.Bits)
            Bits.Add(new BitViewModel(bit));
    }

    public void UpdateValue(ushort value)
    {
        RawValue = value;
        for (int i = 0; i < Bits.Count; i++)
            Bits[i].IsOn = PlcMemory.GetBit(value, Bits[i].BitIndex);
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    protected void OnPropertyChanged([CallerMemberName] string? name = null)
        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
}

/// <summary>
/// 개별 비트 상태 뷰모델
/// </summary>
public class BitViewModel : INotifyPropertyChanged
{
    public int BitIndex { get; }
    public string Address { get; }
    public string Unit { get; }

    private string _name;
    public string Name
    {
        get => _name;
        set
        {
            if (_name == value) return;
            _name = value;
            OnPropertyChanged();
        }
    }

    private bool _isOn;
    public bool IsOn
    {
        get => _isOn;
        set
        {
            if (_isOn == value) return;
            _isOn = value;
            OnPropertyChanged();
            OnPropertyChanged(nameof(DisplayState));
        }
    }

    private bool _isEditing;
    public bool IsEditing
    {
        get => _isEditing;
        set { _isEditing = value; OnPropertyChanged(); }
    }

    public string DisplayState => IsOn ? "ON" : "OFF";

    public BitViewModel(BitInfo info)
    {
        BitIndex = info.Bit;
        Address = info.Address;
        _name = info.Name;
        Unit = info.Unit;
    }

    public event PropertyChangedEventHandler? PropertyChanged;
    protected void OnPropertyChanged([CallerMemberName] string? name = null)
        => PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(name));
}

