// ======== JOG 제어 — MW300 bit6(CW)/bit7(CCW) + MW314-315(JOG속도) ========

/// <summary>
/// JOG 시작 (CW=정방향, CCW=역방향)
/// MW300.bit6=JOG_CW, MW300.bit7=JOG_CCW (APM_VEL FB 경유)
/// MW314~315: JOG 속도 (DINT, 기본값 1000)
/// </summary>
public async Task JogStartAsync(bool isCw)
{
    if (!IsConnected) return;

    // JOG 속도 쓰기 (MW314-315, DINT)
    int jogVel = JogVel > 0 ? JogVel : 1000;
    ushort velL = (ushort)(jogVel & 0xFFFF);
    ushort velH = (ushort)((jogVel >> 16) & 0xFFFF);
    await _client.WriteWordsAsync("%MW314", [velL, velH]);

    // MW300 읽기 → JOG 비트 세팅
    var current = await _client.ReadWordsAsync("%MW300", 1);
    ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
    // 기존 JOG 비트 클리어 후 새 방향 세팅
    val = (ushort)(val & ~0x00C0); // bit6,7 클리어
    val = (ushort)(val | (isCw ? 0x0040 : 0x0080)); // bit6=CW, bit7=CCW
    await _client.WriteWordsAsync("%MW300", [val]);

    LastServoCmd = isCw ? "JOG CW ON" : "JOG CCW ON";
}

/// <summary>
/// JOG 정지 — MW300 bit6,bit7 클리어
/// </summary>
public async Task JogStopAsync()
{
    if (!IsConnected) return;
    var current = await _client.ReadWordsAsync("%MW300", 1);
    ushort val = (current is { Length: > 0 }) ? current[0] : (ushort)0;
    val = (ushort)(val & ~0x00C0); // bit6,7 클리어
    await _client.WriteWordsAsync("%MW300", [val]);
    LastServoCmd = "JOG OFF";
}

