    END_IF;
    IF bDstTimeout THEN
        wErrSource := wErrSource OR 16#0020;
    END_IF;
    IF wVelStat <> 0 THEN
        wErrSource := wErrSource OR 16#0040;
    END_IF;
    %MW415 := wErrSource;

END_IF;

